import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { BillStatus } from '../../core/models';

@Component({
  selector: 'app-bill-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './bill-form.component.html',
  styleUrl: './bill-form.component.css',
})
export class BillFormComponent implements OnInit {
  private fb = inject(FormBuilder);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly statuses: BillStatus[] = ['introduced', 'committee', 'passed', 'signed', 'vetoed'];

  billId = signal<string | null>(null);
  saving = signal(false);
  readonly isEdit = computed(() => !!this.billId());

  form = this.fb.group({
    number: ['', [Validators.required]],
    title: ['', [Validators.required]],
    summary: [''],
    status: ['introduced' as BillStatus, [Validators.required]],
    session: [2025, [Validators.required]],
    sectors: [''],
  });

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    this.billId.set(id);
    if (id) {
      // Mock prefill — service_agent replaces with getBill(id).
      this.form.patchValue({
        number: 'HB0042',
        title: 'Renewable Energy Tax Incentives',
        summary: 'Establishes refundable tax credits for solar and wind installations.',
        status: 'committee',
        session: 2025,
        sectors: 'energy, environment',
      });
    }
  }

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.saving.set(true);
    // Mock save — service_agent wires saveBill()/updateBill().
    const id = this.billId();
    setTimeout(() => {
      this.saving.set(false);
      this.router.navigate(id ? ['/bills', id] : ['/bills']);
    }, 250);
  }

  cancel(): void {
    const id = this.billId();
    this.router.navigate(id ? ['/bills', id] : ['/bills']);
  }
}
